1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
9	
10	const BASE_PREMIUMS: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	  moonstone: 25,
17	};
18	
19	const COMPONENT_BLOCK_PREMIUM: Record<string, number> = {
20	  rune: 60,
21	  moonstone: 60,
22	};
23	
24	function calculateBasePremium(items: any[]): number {
25	  const countsByType: Record<string, number> = {};
26	  for (const item of items) {
27	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
28	  }
29	
30	  let total = 0;
31	  for (const type of Object.keys(countsByType)) {
32	    const count = countsByType[type];
33	    if (count === 3 && COMPONENT_BLOCK_PREMIUM[type] !== undefined) {
34	      total += COMPONENT_BLOCK_PREMIUM[type];
35	    } else {
36	      total += count * BASE_PREMIUMS[type];
37	    }
38	  }
39	  return total;
40	}
41	
42	function calculateItemSurcharges(items: any[]): number {
43	  let surcharges = 0;
44	  for (const item of items) {
45	    const itemBase = BASE_PREMIUMS[item.type];
46	    if (item.cursed) {
47	      surcharges += itemBase * CURSE_SURCHARGE_RATE;
48	    }
49	    if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
50	      surcharges += itemBase * HIGH_ENCHANTMENT_SURCHARGE_RATE;
51	    }
52	  }
53	  return surcharges;
54	}
55	
56	function calculatePremium(items: any[], customer: any, isFollowUp: boolean): number {
57	  const basePremium = calculateBasePremium(items);
58	  const itemSurcharges = calculateItemSurcharges(items);
59	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
60	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
61	  const followUpDiscount = isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
62	  return Math.ceil(basePremium + itemSurcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
63	}
64	
65	export function processScenario(scenario: any): unknown {
66	  const { customer } = scenario;
67	  const results: { premium: number }[] = [];
68	  let quotesSeen = 0;
69	  for (const step of scenario.steps) {
70	    const isFollowUp = quotesSeen > 0;
71	    const premium = calculatePremium(step.items, customer, isFollowUp);
72	    results.push({ premium });
73	    quotesSeen++;
74	  }
75	  return { results };
76	}
